import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"盖塔能源炉","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/2.C级/盖塔能源炉.md","filePath":"4.资源分区/7.物品与装备/4.奇物/2.C级/盖塔能源炉.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/2.C级/盖塔能源炉.md"};function _(l,a,i,p,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"盖塔能源炉",tabindex:"-1"},[s("盖塔能源炉 "),e("a",{class:"header-anchor",href:"#盖塔能源炉","aria-label":'Permalink to "盖塔能源炉"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序007")])])],-1),o('<h1 id="盖塔能源炉-1" tabindex="-1">盖塔能源炉 <a class="header-anchor" href="#盖塔能源炉-1" aria-label="Permalink to &quot;盖塔能源炉&quot;">​</a></h1><p>盖塔能源炉<br> C+3250<br> 科技本质<br> 这是一个体积5的六棱柱，上面画着代表危险的放射性标志。里面不断产生着无尽的盖塔射线，为盖塔机器人提供动力能源。<br> 盖塔射线并不是安全的能源，作为灭绝了恐龙帝国的真凶，盖塔射线虽然不会对人类产生威胁，但若是强行引爆，会对周围的一切造成不可逆转的毁灭性打击。<br> 特殊的：购买盖塔机器人后可以直接取出能源炉引爆，不过作为代价，盖塔机器人将会彻底损毁无法修复。<br> 选开：若取出能源炉并将其引爆的是名为武藏的胖子，那么这次爆炸伤害和范围将会翻倍，同时真盖塔的充能会强制完成。<br> 爆炸物，伤害10L 范围2500m 【毁灭】，并附带1点不可豁免的剧痛点数，对抗伤害的反射豁免会受到12点减值<br> 若要引爆的能源炉来自盖塔机器人，则可以以一个标准动作从机体中取出，移动动作捏爆能源炉来达成殉爆。期间盖塔机器人不会失去动力。<br> 盖塔能源炉可以装入盖塔机器人中：需要进行一个智力手艺：安装，周期为1小时的延长检定，若成功数大于10，则可以将盖塔机器人改造成双核驱动（大嘘），攻击时提供6点能量加值，使用盖塔射线时可以超载能源炉，使这次攻击额外获得5点破甲，武器伤害提升3L。超载能源炉后所有加成失效，但依旧可以用做爆炸物。直到通过一个DC为5的维修检定为止。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
